alter type public.medication_error_status add value if not exists 'approved' after 'awaiting_approval';
alter table public.medication_error_reports add column if not exists approved_by uuid references public.user_profiles(id);

create or replace function public.revise_medication_error(p_report_id uuid,p_reason text,p_title text,p_description text,p_immediate_action text,p_investigation text,p_root_cause_analysis text,p_corrective_actions text,p_preventive_actions text,p_follow_up text,p_verification text,p_closure_notes text) returns void language plpgsql security definer set search_path=public as $$ declare r public.medication_error_reports%rowtype; begin select * into r from public.medication_error_reports where id=p_report_id for update; if not found or r.status='draft' then raise exception 'Only submitted reports may be revised'; end if; if coalesce(trim(p_reason),'')='' then raise exception 'Revision reason required'; end if; if not public.can_medication_error('medication_errors.review',r.tenant_id,r.organization_id,r.facility_id) then raise exception 'Revision permission denied'; end if; insert into public.medication_error_revisions(report_id,tenant_id,organization_id,facility_id,revision,reason,snapshot,created_by) values(r.id,r.tenant_id,r.organization_id,r.facility_id,r.revision,trim(p_reason),to_jsonb(r),auth.uid()); perform set_config('app.medication_error_revision','on',true); update public.medication_error_reports set title=p_title,description=p_description,immediate_action=p_immediate_action,investigation=p_investigation,root_cause_analysis=p_root_cause_analysis,corrective_actions=p_corrective_actions,preventive_actions=p_preventive_actions,follow_up=p_follow_up,verification=p_verification,closure_notes=p_closure_notes,revision=r.revision+1,updated_at=now(),updated_by=auth.uid() where id=r.id; insert into public.medication_error_timeline(report_id,tenant_id,organization_id,facility_id,action,note,created_by) values(r.id,r.tenant_id,r.organization_id,r.facility_id,'report.revised',trim(p_reason),auth.uid()); end $$;

create or replace function public.assign_medication_error(p_report_id uuid,p_owner_id uuid,p_reviewer_id uuid,p_reason text default null) returns void language plpgsql security definer set search_path=public as $$ declare r public.medication_error_reports%rowtype; begin select * into r from public.medication_error_reports where id=p_report_id for update; if not found or not public.can_medication_error('medication_errors.assign',r.tenant_id,r.organization_id,r.facility_id) then raise exception 'Assignment permission denied'; end if; if (r.owner_id is not null and r.owner_id is distinct from p_owner_id or r.reviewer_id is not null and r.reviewer_id is distinct from p_reviewer_id) and coalesce(trim(p_reason),'')='' then raise exception 'Reassignment reason required'; end if; if p_owner_id is not null and not exists(select 1 from public.memberships m where m.user_id=p_owner_id and m.active and m.tenant_id=r.tenant_id and (m.organization_id is null or m.organization_id=r.organization_id) and (m.facility_id is null or m.facility_id=r.facility_id)) then raise exception 'Owner scope mismatch'; end if; if p_reviewer_id is not null and not exists(select 1 from public.memberships m where m.user_id=p_reviewer_id and m.active and m.tenant_id=r.tenant_id and (m.organization_id is null or m.organization_id=r.organization_id) and (m.facility_id is null or m.facility_id=r.facility_id)) then raise exception 'Reviewer scope mismatch'; end if; perform set_config('app.medication_error_controlled','on',true); update public.medication_error_reports set owner_id=p_owner_id,reviewer_id=p_reviewer_id,updated_at=now(),updated_by=auth.uid() where id=r.id; insert into public.medication_error_timeline(report_id,tenant_id,organization_id,facility_id,action,note,created_by) values(r.id,r.tenant_id,r.organization_id,r.facility_id,'report.assigned',p_reason,auth.uid()); end $$;

create or replace function public.update_medication_error_note(p_report_id uuid,p_note_type text,p_note text) returns void language plpgsql security definer set search_path=public as $$ declare r public.medication_error_reports%rowtype; required_permission text; begin select * into r from public.medication_error_reports where id=p_report_id for update; required_permission:=case when p_note_type in ('reviewer','pharmacy') then 'medication_errors.review' when p_note_type in ('manager','quality') then 'medication_errors.approve' else null end; if required_permission is null or not public.can_medication_error(required_permission,r.tenant_id,r.organization_id,r.facility_id) then raise exception 'Note permission denied'; end if; update public.medication_error_reports set reviewer_notes=case when p_note_type='reviewer' then p_note else reviewer_notes end,pharmacy_notes=case when p_note_type='pharmacy' then p_note else pharmacy_notes end,manager_notes=case when p_note_type='manager' then p_note else manager_notes end,quality_notes=case when p_note_type='quality' then p_note else quality_notes end,updated_at=now(),updated_by=auth.uid() where id=r.id; insert into public.medication_error_timeline(report_id,tenant_id,organization_id,facility_id,action,note,created_by) values(r.id,r.tenant_id,r.organization_id,r.facility_id,'report.note_updated',p_note_type,auth.uid()); end $$;

create or replace function public.transition_medication_error(p_report_id uuid,p_to public.medication_error_status,p_reason text default null) returns void language plpgsql security definer set search_path=public as $$ declare r public.medication_error_reports%rowtype; required_permission text; begin select * into r from public.medication_error_reports where id=p_report_id for update; if not found then raise exception 'Report not found'; end if; required_permission:=case when p_to='submitted' then 'medication_errors.submit' when p_to='approved' then 'medication_errors.approve' when p_to='closed' then 'medication_errors.close' when p_to='reopened' then 'medication_errors.reopen' else 'medication_errors.review' end; if not public.can_medication_error(required_permission,r.tenant_id,r.organization_id,r.facility_id) then raise exception 'Workflow permission denied'; end if; if not ((r.status='draft' and p_to='submitted') or (r.status='submitted' and p_to in ('triage','awaiting_information')) or (r.status='triage' and p_to in ('under_investigation','awaiting_information')) or (r.status='under_investigation' and p_to in ('awaiting_information','awaiting_approval','follow_up')) or (r.status='awaiting_information' and p_to in ('triage','under_investigation')) or (r.status='awaiting_approval' and p_to='approved') or (r.status='approved' and p_to='follow_up') or (r.status='follow_up' and p_to in ('verified','under_investigation')) or (r.status='verified' and p_to in ('closed','under_investigation')) or (r.status='closed' and p_to='reopened') or (r.status='reopened' and p_to in ('triage','under_investigation'))) then raise exception 'Invalid workflow transition'; end if; if p_to='submitted' and (r.title='' or r.description='' or r.ncc_merp_category is null) then raise exception 'Submission fields incomplete'; end if; if p_to='closed' and (r.approved_at is null or r.verification is null or r.closure_notes is null) then raise exception 'Closure requires approval, verification, and closure notes'; end if; if p_to='reopened' and coalesce(trim(p_reason),'')='' then raise exception 'Reopen reason required'; end if; perform set_config('app.medication_error_controlled','on',true); update public.medication_error_reports set status=p_to,submitted_at=case when p_to='submitted' then now() else submitted_at end,approved_at=case when p_to='approved' then now() else approved_at end,approved_by=case when p_to='approved' then auth.uid() else approved_by end,closed_at=case when p_to='closed' then now() else closed_at end,reopened_at=case when p_to='reopened' then now() else reopened_at end,updated_at=now(),updated_by=auth.uid() where id=r.id; insert into public.medication_error_timeline(report_id,tenant_id,organization_id,facility_id,action,from_status,to_status,note,created_by) values(r.id,r.tenant_id,r.organization_id,r.facility_id,'workflow.transition',r.status,p_to,p_reason,auth.uid()); end $$;

revoke all on function public.revise_medication_error(uuid,text,text,text,text,text,text,text,text,text,text,text) from public,anon; grant execute on function public.revise_medication_error(uuid,text,text,text,text,text,text,text,text,text,text,text) to authenticated;
revoke all on function public.assign_medication_error(uuid,uuid,uuid,text) from public,anon; grant execute on function public.assign_medication_error(uuid,uuid,uuid,text) to authenticated;
revoke all on function public.update_medication_error_note(uuid,text,text) from public,anon; grant execute on function public.update_medication_error_note(uuid,text,text) to authenticated;
revoke all on function public.transition_medication_error(uuid,public.medication_error_status,text) from public,anon; grant execute on function public.transition_medication_error(uuid,public.medication_error_status,text) to authenticated;
